/// <summary>
///  The <c>ETGOTMSalesLineWritePreSuperOutputContract</c> class is used as data contract for the <c>PuchTableForm</c> class.
/// </summary>
class ETGOTMSalesLineWritePreSuperInputContract implements SysPackable
{
    SalesLine           salesLine;
    boolean             salesTableCheckUpdate;
    SalesTable          salesTable;
    container           salesTablePacked;
    container           salesLinePacked;

    #define.CurrentVersion(1)

    #localmacro.CurrentList
        salesTableCheckUpdate,
        salesTablePacked,
        salesLinePacked
    #endmacro

}

Method.Source:
public container pack()
{
    salesTablePacked = buf2Con(salesTable,true);

    if (SalesLine::hasExensionTableEnabled())
    {
        salesLine.SysExtensionSerializerMap::packAll();
    }

    salesLinePacked  = buf2Con(salesLine,true);
    return [#CurrentVersion,#CurrentList];
}

public SalesLine parmSalesLine (SalesLine _salesLine = salesLine)
{
    salesLine = _salesLine;
    return salesLine;
}

public SalesTable parmSalesTable (SalesTable _salesTable = salesTable)
{
    salesTable = _salesTable;
    return salesTable;
}

public boolean parmSalesTableCheckUpdate (boolean _saledsTableCheckUpdate = salesTableCheckUpdate)
{
    salesTableCheckUpdate = _saledsTableCheckUpdate;
    return salesTableCheckUpdate;
}

public boolean unpack(container _packedClass)
{
    int version     = RunBase::getVersion(_packedClass);

    switch (version)
    {
        case #CurrentVersion:
            [version,#CurrentList] = _packedClass;
            con2Buf(salesTablePacked, salesTable);
            con2Buf(salesLinePacked, salesLine);
            return true;
        default :
            return false;
    }
}

public static ETGOTMSalesLineWritePreSuperInputContract construct()
{
    return new ETGOTMSalesLineWritePreSuperInputContract();
}

/// <summary>
///     Creates an instance of the <c>ETGOTMSalesLineWritePreSuperOutputContract</c> class based on a container from a prior call to <c>PurchLineWritePreSuperInputContract.pack</c> method.
/// </summary>
/// <param name="_packedClass">
///     A <c>Container</c> holding the packed class.
/// </param>
/// <returns>
///     An instance of the <c>ETGOTMSalesLineWritePreSuperOutputContract</c> class identical to the one that was packed into the <c>container</c>.
/// </returns>
static public ETGOTMSalesLineWritePreSuperInputContract create(container _packedClass)
{
    ETGOTMSalesLineWritePreSuperInputContract salesLineWritePreSuperInputContract = ETGOTMSalesLineWritePreSuperInputContract::construct();
    salesLineWritePreSuperInputContract.unpack(_packedClass);
    return salesLineWritePreSuperInputContract;
}
